const body = $input.first().json.body || $input.first().json;

const attendeeEmails = Array.isArray(body.attendee_emails) ? body.attendee_emails : [];
const attendeeCount = attendeeEmails.length;

// Monta o body completo da Google Calendar API
const eventBody = {
  summary: `Reunião de Check-in — ${body.quarter_name}`,
  description: `Check-in do quarter ${body.quarter_name} agendado pelo WenKey.\n\nParticipantes: ${attendeeCount} pessoa(s).`,
  start: {
    dateTime: body.start_datetime,
    timeZone: 'America/Sao_Paulo'
  },
  end: {
    dateTime: body.end_datetime,
    timeZone: 'America/Sao_Paulo'
  },
  attendees: attendeeEmails.map(email => ({ email })),
  conferenceData: {
    createRequest: {
      requestId: body.checkin_id || `wenkey-${Date.now()}`,
      conferenceSolutionKey: {
        type: 'hangoutsMeet'
      }
    }
  },
  guestsCanModifyEvent: false,
  guestsCanInviteOthers: false,
  reminders: {
    useDefault: false,
    overrides: [
      { method: 'email', minutes: 60 },
      { method: 'popup', minutes: 10 }
    ]
  }
};

return [{
  json: {
    event_body: JSON.stringify(eventBody),
    attendee_count: attendeeCount,
    checkin_id: body.checkin_id,
    quarter_name: body.quarter_name
  }
}];
